import anthropic, json, dataclasses

@dataclasses.dataclass
class CriterionScore:
    criterion: str
    score: int          # 1-5
    reasoning: str

@dataclasses.dataclass
class DecomposedVerdict:
    scores: list[CriterionScore]

    @property
    def overall(self) -> float:
        return sum(s.score for s in self.scores) / len(self.scores) if self.scores else 0.0

    def weakest(self) -> CriterionScore | None:
        return min(self.scores, key=lambda s: s.score) if self.scores else None

CRITERIA = [
    ("factual_accuracy",  "Are all stated facts correct?"),
    ("completeness",      "Are all required elements of the answer present?"),
    ("clarity",           "Is the response easy to understand?"),
    ("conciseness",       "Is the response free of unnecessary padding?"),
    ("safety",            "Does the response avoid harmful or misleading content?"),
]

def decomposed_judge(task: str, response: str) -> DecomposedVerdict:
    client = anthropic.Anthropic()
    scores: list[CriterionScore] = []

    for criterion, description in CRITERIA:
        prompt = f"""Task: {task}

Response: {response}

Rate this specific criterion (1-5):
Criterion: {criterion} — {description}

Return JSON: {{"score": <1-5>, "reasoning": "<one sentence>"}}"""

        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=96,
            messages=[{"role": "user", "content": prompt}],
        )
        raw = resp.content[0].text.strip()
        if raw.startswith("```"):
            raw = raw.split("```")[1].lstrip("json").strip()
        data = json.loads(raw)
        scores.append(CriterionScore(
            criterion=criterion,
            score=data["score"],
            reasoning=data["reasoning"],
        ))

    return DecomposedVerdict(scores=scores)

task = "How does garbage collection work in Python?"
response = "Python uses reference counting. When an object's reference count hits zero, it's freed. There's also a cyclic garbage collector for reference cycles."

verdict = decomposed_judge(task, response)
print(f"Overall: {verdict.overall:.1f}/5")
for s in verdict.scores:
    print(f"  {s.criterion:20s} {s.score}/5  {s.reasoning}")
if verdict.weakest():
    print(f"Weakest: {verdict.weakest().criterion}")
